import Sidebar from "@/components/Sidebar";
import Timeline from "@/components/Timeline";

export const dynamic = "force-dynamic";

export default async function Home({
  searchParams,
}: {
  searchParams: Promise<{ [key: string]: string | string[] | undefined }>
}) {
  const resolvedParams = await searchParams;
  const currentSessionId = resolvedParams.session as string | undefined;

  return (
    <main className="flex h-screen bg-neutral-900 overflow-hidden">
      {/* Sidebar Panel */}
      <Sidebar currentSessionId={currentSessionId} />

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col h-full bg-[#1e1e1e] relative">
        {currentSessionId ? (
          <Timeline sessionPk={currentSessionId} />
        ) : (
          <div className="flex items-center justify-center h-full text-neutral-500 text-sm">
            Select a session from the sidebar to view its timeline.
          </div>
        )}
      </div>
    </main>
  );
}
