279	// ---- Collapse silent (continue) step-pairs ----
280	//
281	// A "silent step" is a (user_step_prompt, assistant_continue) pair: the harness
282	// asked the simulator to decide after some agent action, and the simulator
283	// chose to stay silent. These pairs are 80%+ of the timeline and add zero
284	// signal, so we collapse consecutive ones into a single placeholder card.
285	
286	type Item =
287	  | { kind: "msg"; idx: number; msg: Message }
288	  | {
289	      kind: "continues";
290	      from: number;
291	      to: number;
292	      count: number;
293	      // Indexed user-step prompts inside the cluster. We keep these so the
294	      // user can expand the cluster and see the agent activity they reflect,
295	      // but the redundant assistant continue replies are dropped entirely.
296	      userSteps: { idx: number; msg: Message }[];
297	    };
298	
299	function collapseContinues(messages: Message[]): Item[] {
300	  const out: Item[] = [];
301	  let i = 0;
302	  while (i < messages.length) {
303	    const m1 = messages[i];
304	    const m2 = i + 1 < messages.length ? messages[i + 1] : null;
305	    if (
306	      m1.role === "user" &&
307	      m2 &&
308	      m2.role === "assistant" &&
309	      decodeAssistantJson(m2.content)?.decision === "continue"
310	    ) {
311	      const startIdx = i;
312	      const userSteps: { idx: number; msg: Message }[] = [];
313	      while (
314	        i + 1 < messages.length &&
315	        messages[i].role === "user" &&
316	        messages[i + 1].role === "assistant" &&
317	        decodeAssistantJson(messages[i + 1].content)?.decision === "continue"
318	      ) {
319	        userSteps.push({ idx: i, msg: messages[i] });
320	        i += 2;
321	      }
322	      out.push({
323	        kind: "continues",
324	        from: startIdx,
325	        to: i - 1,
326	        count: userSteps.length,
327	        userSteps,
328	      });
329	      continue;
330	    }
331	    out.push({ kind: "msg", idx: i, msg: messages[i] });
332	    i += 1;
333	  }
334	  return out;
335	}
336	
337	function ContinueCluster({
338	  from,
339	  to,
340	  count,
341	  userSteps,
342	}: {
343	  from: number;
344	  to: number;
345	  count: number;
346	  userSteps: { idx: number; msg: Message }[];
347	}) {
348	  const [expanded, setExpanded] = useState(false);
349	  return (
350	    <li className="overflow-hidden rounded-md border border-dashed border-zinc-300 bg-zinc-50/60">
351	      <button
352	        onClick={() => setExpanded((v) => !v)}
353	        className="flex w-full items-center gap-2 px-3 py-1.5 text-left text-[11px] text-zinc-500 hover:bg-zinc-100/60"
354	      >
355	        <span className="font-mono text-zinc-400">
356	          #{from}–{to}
357	        </span>
358	        <span className="flex-1 italic">
359	          {count} silent step{count > 1 ? "s" : ""} hidden · simulator chose{" "}
360	          <span className="font-mono text-zinc-600">continue</span> while the
361	          agent acted
362	        </span>
363	        <span className="font-mono text-[10px] text-zinc-400">
364	          {expanded ? "collapse ▾" : "expand ▸"}
365	        </span>
366	      </button>
367	      {expanded && (
368	        <div className="space-y-2 border-t border-dashed border-zinc-300 bg-white/60 px-3 py-2">
369	          <div className="text-[10px] uppercase tracking-wider text-zinc-400">
370	            agent actions during silent stretch (continue replies omitted)
371	          </div>
372	          <ol className="space-y-2">
373	            {userSteps.map((step) => (
374	              <MessageCard key={step.idx} idx={step.idx} msg={step.msg} />
375	            ))}
376	          </ol>
377	        </div>
378	      )}
379	    </li>
380	  );
381	}
382	
383	// ---- Message card ----
384	
385	function MessageCard({ idx, msg }: { idx: number; msg: Message }) {
386	  const [open, setOpen] = useState(idx < 6);
387	  const decoded = msg.role === "assistant" ? decodeAssistantJson(msg.content) : null;
388	  const decision = decoded?.decision;
389	  const isInterject = decision === "interject";
390	  const isContinue = decision === "continue";
391	
392	  const roleStyle: Record<Role, string> = {
393	    system: "bg-zinc-50 border-zinc-200",
394	    user: "bg-white border-zinc-200",
395	    assistant: isInterject
396	      ? "bg-emerald-50 border-emerald-200"
397	      : isContinue
398	        ? "bg-zinc-50 border-zinc-200"
399	        : "bg-amber-50 border-amber-200",
400	  };
401	  const roleBadge: Record<Role, string> = {
402	    system: "bg-zinc-200 text-zinc-700",
403	    user: "bg-blue-100 text-blue-800",
404	    assistant: isInterject
405	      ? "bg-emerald-200 text-emerald-900"
406	      : isContinue
407	        ? "bg-zinc-200 text-zinc-600"
408	        : "bg-amber-200 text-amber-900",
409	  };
410	
411	  const isLong = msg.content.length > 800;
412	
413	  return (
414	    <li
415	      className={classNames(
416	        "overflow-hidden rounded-md border",
417	        roleStyle[msg.role],
418	      )}
419	    >
420	      <div className="flex items-center justify-between px-3 py-1.5">
421	        <div className="flex items-center gap-2 text-[10px] uppercase tracking-wider">
422	          <span className="font-mono text-zinc-400">#{idx}</span>
423	          <span
424	            className={classNames(
425	              "rounded px-1.5 py-0.5 font-mono text-[10px] font-semibold",
426	              roleBadge[msg.role],
427	            )}
428	          >
429	            {msg.role}
430	          </span>
431	          {decision && (
432	            <span
433	              className={classNames(
434	                "rounded px-1.5 py-0.5 font-mono text-[10px] font-semibold",
435	                isInterject
436	                  ? "bg-emerald-600 text-white"
437	                  : "bg-zinc-400 text-white",
438	              )}
439	            >
440	              {decision}
441	            </span>
442	          )}
443	        </div>
444	        {isLong && (
445	          <button
446	            onClick={() => setOpen((v) => !v)}
447	            className="text-[11px] text-zinc-500 hover:text-zinc-900"
448	          >
449	            {open ? "collapse" : `expand · ${msg.content.length} chars`}
450	          </button>
451	        )}
452	      </div>
453	
454	      {msg.role === "assistant" && decoded ? (
455	        <div className="border-t border-zinc-200 px-3 py-2 text-sm">
456	          <div className="font-mono text-xs text-zinc-500">decision</div>
457	          <div className="mb-2 font-mono text-sm text-zinc-900">
